// ========================================
// OUTCOME TRACKER — Before vs After
// ========================================
const decisions = $('Read All Brain Decisions').all();
const revenue = $('Read Revenue (Outcomes)').all();
const content = $('Read Content (Outcomes)').all();

const now = new Date();
const oneDayAgo = new Date(now - 24 * 60 * 60 * 1000);

// Filter last 24h decisions
const recentDecisions = decisions.filter(d => {
  const ts = new Date(d.json.created_time || d.json.timestamp || 0);
  return ts >= oneDayAgo;
});

// Current metrics
const currentCustomers = revenue.length;
const currentRevenue = revenue.reduce((s, r) => s + (r.json.amount || 350), 0);
const currentAvgScore = content.length > 0
  ? Math.round(content.reduce((s, c) => s + (c.json.performance_score || 0), 0) / content.length)
  : 0;
const currentDMs = content.reduce((s, c) => s + (c.json.dms_generated || 0), 0);

// Track each decision's outcome
const evaluatedDecisions = recentDecisions.map(d => {
  const decision = d.json;
  const customersAtTime = decision.customers_at_time || 0;
  const revenueAtTime = decision.revenue_at_time || 0;

  const customersDelta = currentCustomers - customersAtTime;
  const revenueDelta = currentRevenue - revenueAtTime;

  let outcome = 'neutral';
  if (customersDelta > 2 || revenueDelta > 700) outcome = 'success';
  else if (customersDelta < 0 || revenueDelta < -500) outcome = 'failure';
  else if (customersDelta > 0) outcome = 'partial_success';

  return {
    decision_id: decision.title || 'unknown',
    status: decision.status || '',
    summary: decision.summary || '',
    confidence: decision.confidence_avg || 0,
    pricing_recommended: decision.pricing_recommended || 350,
    before: { customers: customersAtTime, revenue: revenueAtTime },
    after: { customers: currentCustomers, revenue: currentRevenue },
    delta: { customers: customersDelta, revenue: revenueDelta },
    outcome,
    page_id: d.json.id || ''
  };
});

// Aggregate learning
const successCount = evaluatedDecisions.filter(d => d.outcome === 'success').length;
const failureCount = evaluatedDecisions.filter(d => d.outcome === 'failure').length;
const totalEvaluated = evaluatedDecisions.length;
const overallAccuracy = totalEvaluated > 0
  ? Math.round(successCount / totalEvaluated * 100)
  : 0;

// Causal analysis: what decisions led to success?
const successDecisions = evaluatedDecisions.filter(d => d.outcome === 'success');
const failureDecisions = evaluatedDecisions.filter(d => d.outcome === 'failure');

return {
  json: {
    period: {
      from: oneDayAgo.toISOString(),
      to: now.toISOString()
    },
    metrics: {
      current_customers: currentCustomers,
      current_revenue: currentRevenue,
      current_avg_score: currentAvgScore,
      current_dms: currentDMs
    },
    evaluation: {
      total_decisions: totalEvaluated,
      success: successCount,
      failure: failureCount,
      neutral: totalEvaluated - successCount - failureCount,
      accuracy: overallAccuracy
    },
    decisions: evaluatedDecisions,
    success_patterns: successDecisions.map(d => d.summary),
    failure_patterns: failureDecisions.map(d => d.summary)
  }
};

