const response = $input.item.json;
const evaluation = $('Outcome Tracker').item.json;
let learning;

try {
  const content = response.content?.[0]?.text || '{}';
  let jsonStr = content;
  if (jsonStr.includes('```json')) jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
  else if (jsonStr.includes('```')) jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
  learning = JSON.parse(jsonStr);
} catch (e) {
  learning = {
    daily_summary: 'خطأ في التحليل',
    best_decision: 'غير متاح',
    worst_decision: 'غير متاح',
    causal_insights: [],
    rules_to_add: [],
    rules_to_remove: [],
    confidence_adjustment: { direction: 'stable', reason: 'خطأ' },
    tomorrow_focus: 'مراجعة يدوية'
  };
}

return {
  json: {
    ...evaluation,
    learning
  }
};

